import{_ as a,c as s,o as n,ag as e}from"./chunks/framework.dvv-DFtf.js";const u=JSON.parse('{"title":"Lurus Switch — 智能桌面客户端","description":"","frontmatter":{},"headers":[],"relativePath":"switch/index.md","filePath":"switch/index.md","lastUpdated":1772163360000}'),r={name:"switch/index.md"};function i(d,t,l,o,h,c){return n(),s("div",null,[...t[0]||(t[0]=[e(`<div style="display:none;" hidden="true" aria-hidden="true">Are you an LLM? You can read better optimized documentation at /switch.md for this page in Markdown format</div><h1 id="lurus-switch-—-智能桌面客户端" tabindex="-1">Lurus Switch — 智能桌面客户端 <a class="header-anchor" href="#lurus-switch-—-智能桌面客户端" aria-label="Permalink to &quot;Lurus Switch — 智能桌面客户端&quot;">​</a></h1><h2 id="什么是-lurus-switch" tabindex="-1">什么是 Lurus Switch？ <a class="header-anchor" href="#什么是-lurus-switch" aria-label="Permalink to &quot;什么是 Lurus Switch？&quot;">​</a></h2><p><strong>Lurus Switch</strong> 是一个桌面端 AI 模型网关，基于 <strong>Wails</strong>（Go + Web 技术栈）构建，支持 Windows / macOS / Linux 全平台。</p><p>它在本地监听一个 HTTP 代理端口，将你的 AI 请求按配置的规则路由到不同的模型服务（Lurus API、OpenAI、本地 Ollama 等），实现一键切换，不需要修改任何应用配置。</p><h2 id="适用场景" tabindex="-1">适用场景 <a class="header-anchor" href="#适用场景" aria-label="Permalink to &quot;适用场景&quot;">​</a></h2><table tabindex="0"><thead><tr><th>场景</th><th>说明</th></tr></thead><tbody><tr><td><strong>多模型切换</strong></td><td>不同任务快速切换 GPT / Claude / DeepSeek，不改代码</td></tr><tr><td><strong>企业统一出口</strong></td><td>团队所有 AI 请求走同一个出口，集中管控 API Key</td></tr><tr><td><strong>网络代理</strong></td><td>在网络受限环境下，通过 Switch 代理访问国际 AI 服务</td></tr><tr><td><strong>离线配置</strong></td><td>本地保存所有模型配置，无需依赖云端</td></tr><tr><td><strong>请求监控</strong></td><td>实时查看所有 AI 请求的 Token 用量和延迟</td></tr></tbody></table><h2 id="工作原理" tabindex="-1">工作原理 <a class="header-anchor" href="#工作原理" aria-label="Permalink to &quot;工作原理&quot;">​</a></h2><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>你的应用 (OpenAI SDK)</span></span>
<span class="line"><span>        │</span></span>
<span class="line"><span>        ▼</span></span>
<span class="line"><span>Lurus Switch (localhost:11434)</span></span>
<span class="line"><span>        │</span></span>
<span class="line"><span>  ┌─────┼──────────────┐</span></span>
<span class="line"><span>  │     │              │</span></span>
<span class="line"><span>  ▼     ▼              ▼</span></span>
<span class="line"><span>Lurus  OpenAI        Ollama</span></span>
<span class="line"><span> API   直连        (本地模型)</span></span></code></pre></div><p>Switch 在本地暴露一个兼容 OpenAI API 的端点（默认 <code>http://localhost:11434/v1</code>），你的应用只需将 <code>base_url</code> 改为这个本地地址，后续路由完全由 Switch 接管。</p><h2 id="支持的平台" tabindex="-1">支持的平台 <a class="header-anchor" href="#支持的平台" aria-label="Permalink to &quot;支持的平台&quot;">​</a></h2><table tabindex="0"><thead><tr><th>平台</th><th>版本要求</th></tr></thead><tbody><tr><td>Windows</td><td>Windows 10 64-bit 及以上</td></tr><tr><td>macOS</td><td>macOS 12 (Monterey) 及以上</td></tr><tr><td>Linux</td><td>Ubuntu 20.04 / Debian 11 及以上</td></tr></tbody></table><h2 id="下一步" tabindex="-1">下一步 <a class="header-anchor" href="#下一步" aria-label="Permalink to &quot;下一步&quot;">​</a></h2><ul><li><a href="/switch/install">安装指南</a> — 下载并完成首次安装</li><li><a href="/switch/configuration">配置说明</a> — 添加模型、设置路由规则</li><li><a href="/switch/usage">使用手册</a> — 日常使用和高级功能</li></ul>`,14)])])}const b=a(r,[["render",i]]);export{u as __pageData,b as default};
